import { useState } from "react";
import { useNavigate } from "react-router-dom";

const Checkout=({user})=>{
const {cartItems,setCartItems}=useCart();
const navigate =useNavigate();
const [form,setForm]=useState(
    {
        fullname:'',
        email:user?.email ||'',
        address:'',
        city:'',
        postalCode:'',
        paymentMethod:'cod'
    });
    const handleChange=(e)=>{
setForm({...form,[e.target.name]:e.target.value})

    };
    const handleSubmit=async(e)=>{
        e.preventDefault();
        try{
            const order={
             user_id:user._id,
             ...form,
             items:cartItems,
            };
        if(!user)return alert('Please login first');
        if(cartItems.length===0) return alert('Your cart is empty');
          const res=await axios.post('http://localhost:5000/api/orders/checkout', order)
          alert('order placed sucessfully');
          setCartItems([]);
          navigate('/')
    }
        catch(error)
        {
            console.log(error);
            alert('failed to place order')

        }

return(
    <div className="checkout-container">
        <h2>Checkout</h2>
        <form onSubmit={handleSubmit} className="checkout-form">
            <input type="text" name= "fullname" placeholder="Fullname" value={form.fullname} onChange={handleChange} required/>
            <input type="email" name= "email" placeholder="Email" value={form.email} onChange={handleChange} required/>
            <input type="text" name= "address" placeholder="Address" value={form.address} onChange={handleChange} required/>
            <input type="text" name= "city" placeholder="City" value={form.city} onChange={handleChange} required/>
            <input type="text" name= "postalCode" placeholder="Fullname" value={form.city} onChange={handleChange} required/>
            <input type="text" name= "postalCode" placeholder="Fullname" value={form.fullname} onChange={handleChange} required/>
            <input type="text" name= "postalCode" placeholder="PostalCode" value={form.postalCode} onChange={handleChange} required/>
        <select name="paymentMethod" value ={form.paymentMethod} onChange={handleChange}>
            <option>Cash on Delivery</option>
            <option>Credit Card</option>
            <option>Debit Card</option>
            <button type="submit">Place Ordor</button>

        </select>
        </form>
    </div>
)};
}
export default checkout;
